@namespace Lumeo
@implements IAsyncDisposable

<div class="@ContainerClass" @attributes="AdditionalAttributes" id="@(Zoomable ? _zoomContainerId : null)">
    @if (!_hasError)
    {
        <img src="@Src" alt="@Alt"
             width="@Width" height="@Height"
             loading="@(Lazy ? "lazy" : null)"
             class="@ImageClass"
             style="@ZoomStyle"
             @onclick="HandleClick"
             @onerror="HandleError" />
    }
    else if (Fallback is not null)
    {
        <img src="@Fallback" alt="@Alt"
             width="@Width" height="@Height"
             class="@ImageClass" />
    }
    else
    {
        <div class="@FallbackClass" style="@FallbackStyle">
            <Blazicon Svg="Lucide.ImageOff" class="h-8 w-8 text-muted-foreground" />
        </div>
    }

    @if (Preview)
    {
        <div class="absolute inset-0 flex items-center justify-center bg-black/0 hover:bg-black/20 transition-colors cursor-pointer opacity-0 hover:opacity-100"
             @onclick="HandleClick">
            <Blazicon Svg="Lucide.ZoomIn" class="h-6 w-6 text-white drop-shadow-lg" />
        </div>
    }
</div>

@if (_showPreview && Preview)
{
    <div class="fixed inset-0 z-50 bg-black/80 flex items-center justify-center animate-fade-in" role="dialog" aria-modal="true" aria-label="Image preview" @onclick="ClosePreview" @onkeydown="HandlePreviewKeyDown" tabindex="-1" id="@_previewId">
        <button type="button" aria-label="Close preview" class="absolute top-4 right-4 text-white/80 hover:text-white transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80 rounded" @onclick="ClosePreview">
            <Blazicon Svg="Lucide.X" class="h-6 w-6" />
        </button>

        <div class="flex items-center gap-2 absolute bottom-4 left-1/2 -translate-x-1/2">
            <button type="button" class="text-white/80 hover:text-white p-1.5 rounded-md bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80" @onclick="ZoomOut" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ZoomOut" class="h-5 w-5" />
            </button>
            <span class="text-white/80 text-sm min-w-[3rem] text-center">@($"{_zoom}%")</span>
            <button type="button" class="text-white/80 hover:text-white p-1.5 rounded-md bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80" @onclick="ZoomIn" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ZoomIn" class="h-5 w-5" />
            </button>
        </div>

        <img src="@Src" alt="@Alt" class="max-h-[85vh] max-w-[90vw] object-contain transition-transform" style="transform: scale(@(_zoom / 100.0))" @onclick:stopPropagation="true" />
    </div>
}

@inject IComponentInteropService Interop

@code {
    [Parameter] public string? Src { get; set; }
    [Parameter] public string? Alt { get; set; }
    [Parameter] public string? Width { get; set; }
    [Parameter] public string? Height { get; set; }
    [Parameter] public bool Lazy { get; set; }
    [Parameter] public string? Fallback { get; set; }
    [Parameter] public bool Preview { get; set; }
    /// <summary>
    /// When true, registers a two-finger pinch-zoom gesture on the image container
    /// so touch users can zoom in/out on the image directly (independent of the
    /// fullscreen <see cref="Preview"/> overlay). Sets <c>touch-action: none</c>
    /// on the wrapper so the browser doesn't intercept the gesture for native page zoom.
    /// </summary>
    [Parameter] public bool Zoomable { get; set; } = false;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _hasError;
    private bool _showPreview;
    private int _zoom = 100;
    private readonly string _previewId = LumeoIds.New("image-preview");

    // Pinch-zoom state (only used when Zoomable=true).
    private readonly string _zoomContainerId = LumeoIds.New("image-zoom");
    private bool _pinchRegistered;
    private double _zoomScale = 1.0;
    private const double MinZoomScale = 0.5;
    private const double MaxZoomScale = 5.0;
    private string? ZoomStyle => Zoomable && Math.Abs(_zoomScale - 1.0) > 0.0001
        ? $"transform: scale({_zoomScale.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture)}); transform-origin: center center;"
        : null;

    private string ContainerClass => Cx.Join("relative inline-block overflow-hidden", Class);
    private string ImageClass => Cx.Join("object-cover", Cx.When(Preview, "cursor-pointer"));
    private string FallbackClass => "flex items-center justify-center bg-muted rounded-md";
    private string FallbackStyle
    {
        get
        {
            var w = Width is not null ? $"width:{Width}px;" : "width:100%;";
            var h = Height is not null ? $"height:{Height}px;" : "height:8rem;";
            return w + h;
        }
    }

    private void HandleError() => _hasError = true;

    private async Task HandleClick()
    {
        if (Preview && !_hasError)
        {
            _showPreview = true;
            _zoom = 100;
            await Interop.LockScroll();
            // Focus the overlay so Escape / +/- keys work without a click.
            _shouldFocusPreview = true;
        }
    }

    private bool _shouldFocusPreview;

    private async Task ClosePreview()
    {
        _showPreview = false;
        try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
    }

    private void ZoomIn()
    {
        if (_zoom < 300) _zoom += 25;
    }

    private void ZoomOut()
    {
        if (_zoom > 25) _zoom -= 25;
    }

    private async Task HandlePreviewKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape": await ClosePreview(); break;
            case "+":
            case "=": ZoomIn(); break;
            case "-": ZoomOut(); break;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_shouldFocusPreview && _showPreview)
        {
            _shouldFocusPreview = false;
            try { await Interop.FocusElement(_previewId); } catch (JSDisconnectedException) { }
        }

        if (firstRender && Zoomable && !_pinchRegistered)
        {
            _pinchRegistered = true;
            try
            {
                await Interop.RegisterPinchZoom(_zoomContainerId, HandlePinchZoom);
            }
            catch (JSDisconnectedException) { }
        }
    }

    private Task HandlePinchZoom(double scaleDelta)
    {
        // Multiply incremental delta into the running zoom, then clamp.
        var next = _zoomScale * scaleDelta;
        if (next < MinZoomScale) next = MinZoomScale;
        else if (next > MaxZoomScale) next = MaxZoomScale;
        if (Math.Abs(next - _zoomScale) < 0.0001) return Task.CompletedTask;
        _zoomScale = next;
        // The pointermove callbacks fire at high frequency; StateHasChanged is
        // cheap here because only the <img> inline style changes.
        StateHasChanged();
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        if (_showPreview)
        {
            try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
        }
        if (_pinchRegistered)
        {
            try { await Interop.UnregisterPinchZoom(_zoomContainerId); } catch (JSDisconnectedException) { }
        }
    }
}

@namespace Lumeo
@implements IAsyncDisposable

<div class="@CssClass" @attributes="AdditionalAttributes">
    @if (Images is { Count: > 0 })
    {
        @foreach (var (image, index) in Images.Select((img, i) => (img, i)))
        {
            <button @key="image.Src" type="button"
                    class="overflow-hidden rounded-md cursor-pointer group focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2"
                    aria-label="@($"Open image {index + 1}")"
                    @onclick="() => OpenPreview(index)">
                <img src="@image.Src" alt="@image.Alt" loading="lazy"
                     class="w-full h-full object-cover transition-transform group-hover:scale-105" />
            </button>
        }
    }
</div>

@if (_showPreview && Images is { Count: > 0 })
{
    <div class="fixed inset-0 z-50 bg-black/80 flex items-center justify-center animate-fade-in" role="dialog" aria-modal="true" aria-label="Image preview" @onkeydown="HandleKeyDown" tabindex="-1" id="@_previewId">
        <button type="button" class="absolute top-4 right-4 text-white/80 hover:text-white transition-colors z-10 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80 rounded" @onclick="ClosePreview">
            <Blazicon Svg="Lucide.X" class="h-6 w-6" />
        </button>

        @if (Images.Count > 1)
        {
            <button type="button" class="absolute left-4 top-1/2 -translate-y-1/2 text-white/80 hover:text-white p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80"
                    @onclick="PrevImage" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ChevronLeft" class="h-6 w-6" />
            </button>
            <button type="button" class="absolute right-4 top-1/2 -translate-y-1/2 text-white/80 hover:text-white p-2 rounded-full bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80"
                    @onclick="NextImage" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ChevronRight" class="h-6 w-6" />
            </button>
        }

        <div class="flex items-center gap-2 absolute bottom-4 left-1/2 -translate-x-1/2 z-10">
            <button type="button" class="text-white/80 hover:text-white p-1.5 rounded-md bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80" @onclick="ZoomOut" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ZoomOut" class="h-5 w-5" />
            </button>
            <span class="text-white/80 text-sm min-w-[3rem] text-center">@($"{_zoom}%")</span>
            <button type="button" class="text-white/80 hover:text-white p-1.5 rounded-md bg-white/10 hover:bg-white/20 transition-colors focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-white focus-visible:ring-offset-2 focus-visible:ring-offset-black/80" @onclick="ZoomIn" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.ZoomIn" class="h-5 w-5" />
            </button>
            @if (Images.Count > 1)
            {
                <span class="text-white/60 text-sm ml-2">@(_currentIndex + 1) / @Images.Count</span>
            }
        </div>

        <img src="@Images[_currentIndex].Src" alt="@Images[_currentIndex].Alt"
             class="max-h-[85vh] max-w-[90vw] object-contain transition-transform"
             style="transform: scale(@(_zoom / 100.0))"
             id="@_previewImageId"
             @onclick:stopPropagation="true" />
    </div>
}

@inject IComponentInteropService Interop
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts

@code {
    [Parameter] public List<ImageItem>? Images { get; set; }
    [Parameter] public int Columns { get; set; } = 3;
    [Parameter] public string? Gap { get; set; }
    /// <summary>
    /// When true (default), enables horizontal swipe (prev/next image) and
    /// pinch-to-zoom gestures on the fullscreen preview overlay on touch devices.
    /// </summary>
    [Parameter] public bool GesturesEnabled { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _showPreview;
    private int _currentIndex;
    private int _zoom = 100;
    private readonly string _previewId = LumeoIds.New("gallery-preview");
    private readonly string _previewImageId = LumeoIds.New("gallery-img");

    // Gesture state
    private bool _pinchRegistered;
    private bool _swipeRegistered;
    private bool _shouldFocusPreview;

    private const int MinZoom = 25;
    private const int MaxZoom = 300;

    private string CssClass
    {
        get
        {
            var cols = Columns switch
            {
                1 => "grid-cols-1",
                2 => "grid-cols-2",
                3 => "grid-cols-3",
                4 => "grid-cols-4",
                5 => "grid-cols-5",
                6 => "grid-cols-6",
                _ => "grid-cols-3"
            };
            var gap = Gap ?? "gap-2";
            return $"grid {cols} {gap} {Class}".Trim();
        }
    }

    private async Task OpenPreview(int index)
    {
        _currentIndex = index;
        _zoom = 100;
        _showPreview = true;
        await Interop.LockScroll();
        // Focus the overlay so Escape / arrow-key navigation work without
        // requiring the user to click the overlay first (the wrapper has
        // tabindex="-1" so keyboard events would otherwise never fire).
        _shouldFocusPreview = true;
    }

    private async Task ClosePreview()
    {
        _showPreview = false;
        await UnregisterGesturesAsync();
        _pinchRegistered = false;
        _swipeRegistered = false;
        try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
    }

    private void PrevImage()
    {
        if (Images is null) return;
        _currentIndex = (_currentIndex - 1 + Images.Count) % Images.Count;
        _zoom = 100;
    }

    private void NextImage()
    {
        if (Images is null) return;
        _currentIndex = (_currentIndex + 1) % Images.Count;
        _zoom = 100;
    }

    private void ZoomIn()
    {
        if (_zoom < MaxZoom) _zoom += 25;
    }

    private void ZoomOut()
    {
        if (_zoom > MinZoom) _zoom -= 25;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape": await ClosePreview(); break;
            case "ArrowLeft": PrevImage(); break;
            case "ArrowRight": NextImage(); break;
            case "+":
            case "=": ZoomIn(); break;
            case "-": ZoomOut(); break;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (_shouldFocusPreview && _showPreview)
        {
            _shouldFocusPreview = false;
            try { await Interop.FocusElement(_previewId); } catch (JSDisconnectedException) { }
        }

        if (_showPreview && GesturesEnabled)
        {
            // Register pinch zoom on the preview image element.
            if (!_pinchRegistered)
            {
                _pinchRegistered = true;
                try
                {
                    await Interop.RegisterPinchZoom(_previewImageId, HandlePinchZoom);
                }
                catch (JSDisconnectedException) { }
            }

            // Register horizontal swipe on the preview overlay (for prev/next).
            if (!_swipeRegistered && Images is { Count: > 1 })
            {
                _swipeRegistered = true;
                try
                {
                    await Interop.RegisterGallerySwipe(_previewId, HandleGallerySwipe, GestureOpts.Value.SwipeThresholdPx, GestureOpts.Value.VerticalDeadZonePx);
                }
                catch (JSDisconnectedException) { }
            }
        }
    }

    private Task HandlePinchZoom(double scaleDelta)
    {
        // scaleDelta is a multiplicative factor (currentDistance / previousDistance).
        // Multiply into current zoom percentage and clamp to [MinZoom, MaxZoom].
        var next = (int)Math.Round(_zoom * scaleDelta);
        if (next < MinZoom) next = MinZoom;
        else if (next > MaxZoom) next = MaxZoom;
        if (next == _zoom) return Task.CompletedTask;
        _zoom = next;
        StateHasChanged();
        return Task.CompletedTask;
    }

    private Task HandleGallerySwipe(string direction)
    {
        if (Images is null || Images.Count <= 1) return Task.CompletedTask;
        if (direction == "next")
            NextImage();
        else
            PrevImage();
        StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task UnregisterGesturesAsync()
    {
        if (_pinchRegistered)
        {
            try { await Interop.UnregisterPinchZoom(_previewImageId); } catch (JSDisconnectedException) { }
        }
        if (_swipeRegistered)
        {
            try { await Interop.UnregisterGallerySwipe(_previewId); } catch (JSDisconnectedException) { }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_showPreview)
        {
            await UnregisterGesturesAsync();
            try { await Interop.UnlockScroll(); } catch (JSDisconnectedException) { }
        }
    }

    public record ImageItem(string Src, string? Alt = null);
}
